import{_ as e,c as a,o,a as r}from"./app.ee2751a3.js";const f=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[{"level":2,"title":"Available Models","slug":"available-models"}],"relativePath":"guide/introduction.md"}'),t={name:"guide/introduction.md"},n=r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-hidden="true">#</a></h1><p>HuSpaCy is a <a href="https://spacy.io" target="_blank" rel="noopener noreferrer">spaCy</a> library providing industrial-strength Hungarian language processing facilities through spaCy models. The released pipelines consist of a tokenizer, sentence splitter, lemmatizer, tagger (predicting morphological features as well), dependency parser and a named entity recognition module. Word and phrase embeddings are also available through spaCy&#39;s API. All models have high throughput, decent memory usage and close to state-of-the-art accuracy. A live demo is available <a href="https://huggingface.co/spaces/huspacy/demo" target="_blank" rel="noopener noreferrer">here</a>, model releases are published to <a href="https://huggingface.co/huspacy/" target="_blank" rel="noopener noreferrer">Hugging Face Hub</a>.</p><h2 id="available-models" tabindex="-1">Available Models <a class="header-anchor" href="#available-models" aria-hidden="true">#</a></h2><p>We provide two models, the first one is a CNN-based large model which achieves a good balance between accuracy and processing speed. This default model (<a href="/docs/lg/"><code>hu_core_news_lg</code></a>) provides tokenization, sentence splitting, part-of-speech tagging (UD labels w/ detailed morphosyntactic features), lemmatization, dependency parsing and named entity recognition and ships with pretrained word vectors.</p><p>The second model (<a href="/docs/trf/"><code>hu_core_news_trf</code></a>) is built on <a href="https://huggingface.co/SZTAKI-HLT/hubert-base-cc" target="_blank" rel="noopener noreferrer">huBERT</a> and provides the same functionality as the large model except the word vectors. It comes with much higher accuracy in the price of increased computational resource usage. We suggest using it with GPU support.</p><p>A demo of these models is available at <a href="https://huggingface.co/spaces/huspacy/demo" target="_blank" rel="noopener noreferrer">Hugging Face Spaces</a>. Models&#39; changes are recorded in respective changelog files. (<a href="/docs/lg/changelog.html"><code>lg</code></a>, <a href="/docs/trf/changelog.html"><code>trf</code></a>, <a href="/docs/lg_vectors/changelog.html"><code>vectors</code></a>)</p>',6),s=[n];function i(c,d,l,h,g,p){return o(),a("div",null,s)}var m=e(t,[["render",i]]);export{f as __pageData,m as default};
